package com.cognizant.springlearn.controller; import com.cognizant.springlearn.model.Employee; import com.cognizant.springlearn.service.EmployeeService; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.util.List; @RestController public class EmployeeController { private final EmployeeService employeeService; public EmployeeController(EmployeeService employeeService){this.employeeService=employeeService;} @GetMapping("/employees") public List<Employee> getAllEmployees(){return employeeService.getAllEmployees();} @PutMapping("/employees/{id}") public Employee updateEmployee(@PathVariable int id, @RequestBody Employee employee){return employeeService.updateEmployee(id, employee);} @DeleteMapping("/employees/{id}") public ResponseEntity<Void> deleteEmployee(@PathVariable int id){employeeService.deleteEmployee(id); return ResponseEntity.noContent().build();} }
